-- Update some completion dates for completed courses
UPDATE user_course_enrollments 
SET completion_date = enrolled_at + INTERVAL '20 days',
    certificate_issued = true,
    certificate_url = 'https://certificates.example.com/cert-' || id || '.pdf'
WHERE status = 'completed';

-- Add some ratings and reviews for completed courses
UPDATE user_course_enrollments 
SET rating = 5,
    review = 'Excellent course! The instructor was very knowledgeable and the content was well-structured. I learned a lot and feel confident applying these skills in my work.'
WHERE user_id = '11111111-1111-1111-1111-111111111111' AND course_id = 2;

UPDATE user_course_enrollments 
SET rating = 4,
    review = 'Great course with practical examples. The assignments were challenging but helped reinforce the concepts. Would recommend to anyone looking to get started in this field.'
WHERE user_id = '22222222-2222-2222-2222-222222222222' AND course_id = 4;

